using System;
using System.Diagnostics;
using SkiaSharp;

// Simulate #1680: SKPath memory leak during rapid surface recreation
const int iterations = 2000;
const int pathsPerFrame = 50;

long memStart = Process.GetCurrentProcess().WorkingSet64;
Console.WriteLine($"Initial memory: {memStart / 1024.0 / 1024.0:F2} MB");

// Test: Surface recreation with path drawing (simulating resize)
for (int i = 0; i < iterations; i++)
{
    int w = 800 + (i % 200);
    int h = 600 + (i % 200);
    using var surface = SKSurface.Create(new SKImageInfo(w, h));
    var canvas = surface.Canvas;
    canvas.Clear(SKColors.White);
    using var paint = new SKPaint { Color = SKColors.Blue, IsAntialias = true, Style = SKPaintStyle.Stroke, StrokeWidth = 2 };
    for (int j = 0; j < pathsPerFrame; j++)
    {
        using var path = new SKPath();
        path.MoveTo(j * 10 + i % 100, j * 5);
        path.LineTo(w - j * 10 - i % 100, h / 2);
        path.QuadTo(w / 2, h - j * 5, j * 15, h / 3);
        path.CubicTo(100 + j + i, 200 + j, 300 - j, 400 - j + i, w / 2, h / 2);
        path.Close();
        canvas.DrawPath(path, paint);
    }
    canvas.Flush();
    if (i % 500 == 0) { GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect(); long memNow = Process.GetCurrentProcess().WorkingSet64; Console.WriteLine($"  Frame {i,5}: {memNow / 1024.0 / 1024.0:F2} MB (delta: +{(memNow - memStart) / 1024.0 / 1024.0:F2} MB)"); }
}
GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
long memFinal = Process.GetCurrentProcess().WorkingSet64;
Console.WriteLine($"Final: {memFinal / 1024.0 / 1024.0:F2} MB (delta: +{(memFinal - memStart) / 1024.0 / 1024.0:F2} MB, ratio: {(double)memFinal / memStart:F2}x)");
Console.WriteLine("SUCCESS: test completed");
